根据我对项目的分析，我为你准备了一个**具体的、可实施的小改进任务**：

---

## 🎯 小改进任务：为 Dashboard 类型系统添加运行时验证

### 📋 任务背景

当前 Dashboard 模块定义了完善的 TypeScript 类型（`src/dashboard/types.ts`），但缺少**运行时类型验证**。这可能导致：
- WebSocket 消息数据格式错误时难以发现问题
- API 请求数据不合法导致运行时错误
- 缺少对 `unknown` 类型的安全检查

### 🎯 改进目标

创建一个**类型验证工具模块**，为核心类型添加运行时验证能力。

---

### 📝 具体任务清单

#### 1. 创建类型验证工具模块

**新建文件**: `src/dashboard/utils/validators.ts`

```typescript
/**
 * 类型验证工具
 * 为 Dashboard 类型提供运行时验证
 */

import { 
  IterationStatus, 
  AgentStatus, 
  AgentType,
  ProjectStatus,
  LogLevel 
} from '../types';

// ==================== 枚举验证器 ====================

export function isIterationStatus(value: unknown): value is IterationStatus {
  return typeof value === 'string' && 
    ['running', 'completed', 'failed', 'cancelled'].includes(value);
}

export function isAgentStatus(value: unknown): value is AgentStatus {
  return typeof value === 'string' && 
    ['idle', 'running', 'completed', 'error'].includes(value);
}

export function isAgentType(value: unknown): value is AgentType {
  return typeof value === 'string' && 
    [
      'product-manager', 'architect', 'frontend', 'backend', 
      'database', 'ui-designer', 'tester', 'security', 
      'documenter', 'assets'
    ].includes(value);
}

// ==================== 对象验证器 ====================

export function isValidIteration(data: unknown): data is Iteration {
  if (!data || typeof data !== 'object') return false;

  const d = data as Record<string, unknown>;
  return (
    typeof d.id === 'number' &&
    typeof d.iterationNumber === 'number' &&
    isIterationStatus(d.status) &&
    (d.requirement === null || typeof d.requirement === 'string') &&
    d.startedAt instanceof Date
  );
}

export function isValidAgentState(data: unknown): data is AgentState {
  if (!data || typeof data !== 'object') return false;

  const d = data as Record<string, unknown>;
  return (
    typeof d.id === 'number' &&
    typeof d.agentName === 'string' &&
    isAgentType(d.agentType) &&
    isAgentStatus(d.status) &&
    typeof d.progress === 'number' &&
    d.progress >= 0 && d.progress <= 100
  );
}

// ==================== WebSocket 消息验证器 ====================

export function isWSEvent(data: unknown): data is WSEvent {
  if (!data || typeof data !== 'object') return false;

  const d = data as Record<string, unknown>;
  if (typeof d.event !== 'string') return false;

  switch (d.event) {
    case 'iteration.status_changed':
      return isValidIterationStatusChange(d.data);
    case 'agent.status_changed':
      return isValidAgentStatusChange(d.data);
    case 'iteration.progress':
      return isValidIterationProgress(d.data);
    case 'system.metrics':
      return isValidSystemMetricsEvent(d.data);
    default:
      return false;
  }
}

function isValidIterationStatusChange(data: unknown): boolean {
  if (!data || typeof data !== 'object') return false;
  const d = data as Record<string, unknown>;
  return (
    typeof d.iterationId === 'number' &&
    typeof d.iterationNumber === 'number' &&
    isIterationStatus(d.status)
  );
}

function isValidAgentStatusChange(data: unknown): boolean {
  if (!data || typeof data !== 'object') return false;
  const d = data as Record<string, unknown>;
  return (
    typeof d.iterationId === 'number' &&
    typeof d.agentName === 'string' &&
    isAgentType(d.agentType) &&
    isAgentStatus(d.status)
  );
}

// ... 其他验证器

// ==================== 错误类型 ====================

export class ValidationError extends Error {
  constructor(
    public fieldName: string,
    public receivedValue: unknown,
    public expectedType: string
  ) {
    super(`Validation failed: ${fieldName} expected ${expectedType}, got ${typeof receivedValue}`);
    this.name = 'ValidationError';
  }
}

// ==================== 验证辅助函数 ====================

export function assertValidIteration(data: unknown): asserts data is Iteration {
  if (!isValidIteration(data)) {
    throw new ValidationError('iteration', data, 'Iteration');
  }
}

export function assertValidAgentState(data: unknown): asserts data is AgentState {
  if (!isValidAgentState(data)) {
    throw new ValidationError('agentState', data, 'AgentState');
  }
}
```

---

#### 2. 更新 RealtimeService 使用验证器

**修改文件**: `src/dashboard/services/realtime.service.ts`

```typescript
import { isWSEvent, ValidationError } from '../utils/validators';

export class RealtimeService {
  // ... 现有代码

  /**
   * 处理客户端消息（带验证）
   */
  handleMessage(client: WebSocket, rawMessage: string): void {
    try {
      const message = JSON.parse(rawMessage);

      // 验证 WebSocket 消息格式
      if (!isWSEvent(message)) {
        client.send(JSON.stringify({
          error: 'Invalid message format',
          received: rawMessage
        }));
        return;
      }

      // 处理验证后的消息
      this.handleValidatedMessage(client, message);
    } catch (error) {
      if (error instanceof ValidationError) {
        console.error('WebSocket validation error:', error.message);
      } else {
        console.error('WebSocket message parse error:', error);
      }
    }
  }

  private handleValidatedMessage(client: WebSocket, message: WSEvent): void {
    // 类型已验证，安全使用
    switch (message.event) {
      case 'iteration.status_changed':
        this.broadcastToChannel('iteration', message);
        break;
      // ... 其他 case
    }
  }
}
```

