#### 3. 添加单元测试

**新建文件**: `tests/dashboard/dashboard-validators.test.ts`

```typescript
import { describe, it, expect } from '@jest/globals';
import {
  isIterationStatus,
  isAgentType,
  isValidIteration,
  isValidAgentState,
  isWSEvent,
  assertValidIteration,
  ValidationError
} from '../../src/dashboard/utils/validators';
import { IterationStatus, AgentType } from '../../src/dashboard/types';

describe('Dashboard - 类型验证器', () => {
  describe('枚举验证器', () => {
    it('应该验证有效的迭代状态', () => {
      expect(isIterationStatus('running')).toBe(true);
      expect(isIterationStatus('completed')).toBe(true);
      expect(isIterationStatus('invalid')).toBe(false);
      expect(isIterationStatus(null)).toBe(false);
      expect(isIterationStatus(123)).toBe(false);
    });

    it('应该验证有效的 Agent 类型', () => {
      expect(isAgentType('architect')).toBe(true);
      expect(isAgentType('invalid')).toBe(false);
    });
  });

  describe('对象验证器', () => {
    it('应该验证有效的迭代对象', () => {
      const validIteration = {
        id: 1,
        iterationNumber: 1,
        status: IterationStatus.RUNNING,
        requirement: '测试需求',
        startedAt: new Date(),
        // ... 其他必需字段
      };

      expect(isValidIteration(validIteration)).toBe(true);
      expect(isValidIteration(null)).toBe(false);
      expect(isValidIteration({})).toBe(false);
    });

    it('应该验证 Agent 进度范围', () => {
      const validAgent = {
        id: 1,
        agentName: '架构师',
        agentType: AgentType.ARCHITECT,
        status: 'running',
        progress: 50,
        // ... 其他必需字段
      };

      expect(isValidAgentState(validAgent)).toBe(true);
      expect(isValidAgentState({ ...validAgent, progress: -1 })).toBe(false);
      expect(isValidAgentState({ ...validAgent, progress: 101 })).toBe(false);
    });
  });

  describe('断言函数', () => {
    it('应该对有效数据不断言', () => {
      const valid = {
        id: 1,
        iterationNumber: 1,
        status: IterationStatus.RUNNING,
        requirement: '测试',
        startedAt: new Date()
      };

      expect(() => assertValidIteration(valid)).not.toThrow();
    });

    it('应该对无效数据抛出 ValidationError', () => {
      expect(() => assertValidIteration(null)).toThrow(ValidationError);
      expect(() => assertValidIteration({})).toThrow(ValidationError);
    });
  });
});
```

